
'use client';
import React, { useState, useEffect } from 'react';
import { getLibraryBorrowingsAction } from '@/app/actions/dbActions';
import { LibraryBorrowing } from '@/utils/storage';

export default function BorrowRecords() {
  const [records, setRecords] = useState<LibraryBorrowing[]>([]);

  useEffect(() => {
    loadRecords();
  }, []);

  const loadRecords = async () => {
    const allRecords = await getLibraryBorrowingsAction();
    setRecords(allRecords.sort((a, b) => new Date(b.borrowDate).getTime() - new Date(a.borrowDate).getTime()));
  };

  return (
    <div>
      <h2 className="text-3xl mb-2">Borrow Records</h2>
      <p className="text-gray-600 mb-8">Complete history of book borrowing</p>

      <div className="bg-white rounded-xl shadow-lg overflow-x-auto">
        <table className="w-full">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-4 text-left">Book ID</th>
              <th className="px-4 py-4 text-left">Student ID</th>
              <th className="px-4 py-4 text-left">Borrowed</th>
              <th className="px-4 py-4 text-left">Due Date</th>
              <th className="px-4 py-4 text-left">Returned</th>
              <th className="px-4 py-4 text-left">Status</th>
            </tr>
          </thead>
          <tbody>
            {records.map((record) => {
              const isOverdue = !record.returnDate && new Date() > new Date(record.dueDate);
              const isActive = !record.returnDate;

              return (
                <tr key={record.id} className="border-t hover:bg-gray-50">
                  <td className="px-4 py-4">{record.bookId}</td>
                  <td className="px-4 py-4">{record.studentId}</td>
                  <td className="px-4 py-4 text-sm">
                    {new Date(record.borrowDate).toLocaleDateString()}
                  </td>
                  <td className="px-4 py-4 text-sm">
                    {new Date(record.dueDate).toLocaleDateString()}
                  </td>
                  <td className="px-4 py-4 text-sm">
                    {record.returnDate ? new Date(record.returnDate).toLocaleDateString() : '-'}
                  </td>
                  <td className="px-4 py-4">
                    <span className={`px-3 py-1 rounded-full text-sm ${
                      isOverdue ? 'bg-red-100 text-red-800' :
                      isActive ? 'bg-blue-100 text-blue-800' :
                      'bg-gray-100 text-gray-800'
                    }`}>
                      {isOverdue ? 'Overdue' : isActive ? 'Active' : 'Returned'}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
